  var Telemetry = (function () {
    var QUEUE_KEY = 'app_telemetry_queue';
    var MAX_QUEUE_SIZE = 200;
    var MAX_BATCH_SIZE = 50;
    var FLUSH_DEBOUNCE_MS = 5000;
    var flushTimer = null;

    function getDeviceId() {
      try {
        var id = localStorage.getItem('app_device_id');
        if (id) return id;
        id = (crypto && crypto.randomUUID) ? crypto.randomUUID() :
          'tv-' + Date.now() + '-' + Math.random().toString(16).slice(2);
        localStorage.setItem('app_device_id', id);
        return id;
      } catch (e) { return 'tv-unknown'; }
    }

    function getQueue() {
      try { return JSON.parse(localStorage.getItem(QUEUE_KEY) || '[]'); }
      catch (e) { return []; }
    }

    function setQueue(queue) {
      try { localStorage.setItem(QUEUE_KEY, JSON.stringify(queue.slice(-MAX_QUEUE_SIZE))); }
      catch (e) {}
    }

    function record(eventType, payload) {
      var queue = getQueue();
      queue.push({ event_type: eventType, ts: Date.now(), payload: payload || {} });
      setQueue(queue);
      if (queue.length >= MAX_BATCH_SIZE) flushSoon();
    }

    function flushSoon() {
      if (flushTimer) return;
      flushTimer = setTimeout(function () {
        flushTimer = null;
        flush();
      }, FLUSH_DEBOUNCE_MS);
    }

    function flush() {
      var queue = getQueue();
      if (!queue.length) return;
      var batch = queue.slice(0, MAX_BATCH_SIZE);
      appFetch(settings.serverUrl + '/api/telemetry', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ device_id: getDeviceId(), source: 'tv_apk', events: batch }),
      }).then(function (r) {
        if (!r.ok) return;
        setQueue(getQueue().slice(batch.length));
      }).catch(function () {}); // best-effort; batch stays queued for next flush
    }

    return { record: record, flush: flush, flushSoon: flushSoon };
  }());

