  // Blob + hash are written in the SAME readwrite transaction, so IndexedDB's
  // own atomicity guarantees the pairing: if the app is killed mid-write the
  // whole transaction aborts and the previous (valid) cache entry is untouched.
  // cb(err) fires only once the transaction actually commits.
  function _idbPutGlb(buf, modelHash, cb) {
    _idbOpen(function(db) {
      try {
        var tx = db.transaction(_IDB_STOR, 'readwrite');
        var store = tx.objectStore(_IDB_STOR);
        store.put(buf, _IDB_KEY);
        if (modelHash) store.put(modelHash, _IDB_HASH_KEY);
        tx.oncomplete = function() {
          blog('GLB: salvo no IndexedDB (hash=' + modelHash + ')');
          if (cb) cb(null);
        };
        tx.onerror = function() { if (cb) cb(tx.error); };
      } catch(e) { blog('GLB: IndexedDB write fail: ' + e); if (cb) cb(e); }
    }, function(e) { blog('GLB: IndexedDB open fail: ' + e); if (cb) cb(e); });
  }
