      function pollLoginStatus() {
    if (!_loginSession.token || _loginSession.status !== 'active') return;
    
    var url = settings.serverUrl + '/api/auth/auth_status.json?token=' + _loginSession.token;
    appFetch(url).then(function(res) {
      if (!res || !res.ok) return;
      return res.json();
    }).then(function(data) {
      if (!data) return;
      
      if (data.status === 'success') {
        blog('Login: success! exchanging session_token for userId');
        _loginSession.status = 'success';
        clearTimeout(_loginSession.pollTimer);
        clearTimeout(_loginSession.refreshTimer);

        appFetch(settings.serverUrl + '/api/auth/tv_exchange', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ session_token: data.session_token }),
        }).then(function (r) {
          if (!r || !r.ok) throw new Error('Exchange failed');
          return r.json();
        }).then(function (exchangeData) {
          settings.userName = data.userName;
          settings.userId = exchangeData.userId;
          persistSettings();

          // Refresh safely
          var panel = document.getElementById('app-settings-panel');
          if (panel && panel.style.display !== 'none') {
             _goBack();
          }
          currentVideoId = null;
          init();
        }).catch(function (e) {
          blog('Login: exchange error: ' + e);
        });
      } else if (data.status === 'expired') {
        blog('Login: token expired');
        _loginSession.status = 'idle';
        requestLoginToken();
      } else {
        // Pending
        _loginSession.pollTimer = setTimeout(pollLoginStatus, 4000);
      }
    }).catch(function(e) {
      _loginSession.pollTimer = setTimeout(pollLoginStatus, 5000);
    });
  }

  function requestLoginToken() {
    if (_loginSession.status === 'loading' || _loginSession.status === 'active' || _loginSession.status === 'success') return;
    
    if (_loginSession.cycles >= 2) {
      _loginSession.status = 'expired';
      var statusEl = document.getElementById('app-login-status-text');
      if (statusEl) { 
        statusEl.textContent = 'Sessão expirada. Reabra o menu.'; 
        statusEl.style.color = '#cc0000'; 
      }
      return;
    }

    _loginSession.status = 'loading';
    var url = settings.serverUrl + '/api/auth/auth_init.json';
    
    blog('Login: fetching token via ' + url);
    
    appFetch(url).then(function(res) {
      if (!res || !res.ok) throw new Error('Init failed');
      return res.json();
    }).then(function(data) {
      if (!data || !data.token) throw new Error('Invalid response');
      
      _loginSession.token = data.token;
      _loginSession.expiresAt = Date.now() + (data.expires_in || 300) * 1000;
      _loginSession.cycles++;
      _loginSession.status = 'active';
      
      // Atomic updates
      var tokenEl = document.getElementById('app-login-token');
      if (tokenEl) tokenEl.textContent = data.token;
      
      clearTimeout(_loginSession.refreshTimer);
      _loginSession.refreshTimer = setTimeout(function() {
        _loginSession.status = 'idle';
        requestLoginToken();
      }, (data.expires_in || 300) * 1000 + 1000);
      
      clearTimeout(_loginSession.pollTimer);
      pollLoginStatus();
      
    }).catch(function(e) {
      blog('Login: network error: ' + e);
      _loginSession.status = 'idle';
      setTimeout(requestLoginToken, 10000);
    });
  }

