              var hasLibras = result.some(function(b) { return b && b.type === 'APP'; });
              if (hasLibras) return result;
              var librasBtn;
              try {
                librasBtn = JSON.parse(JSON.stringify(result[0]));
                librasBtn.type = 'APP';
                if (librasBtn.button && librasBtn.button.buttonRenderer) {
                  var br = librasBtn.button.buttonRenderer;
                  if (br.icon) br.icon.iconType = 'CLOSED_CAPTION';
                  if (br.accessibility) br.accessibility.label = 'Tradutor Libras';
                  br.tooltip = 'Tradutor Libras';
                  br.serviceEndpoint = { customAction: { action: 'APP_SETTINGS' } };
                }
              } catch(ex) {
                librasBtn = {
                  type: 'APP',
                  button: { buttonRenderer: {
                    icon: { iconType: 'CLOSED_CAPTION' },
                    accessibility: { label: 'Tradutor Libras' },
                    tooltip: 'Tradutor Libras',
                    serviceEndpoint: { customAction: { action: 'APP_SETTINGS' } }
                  }}
                };
              }
              var hasGear = result.some(function(b) { return b && b.type === 'TRANSPORT_CONTROLS_BUTTON_TYPE_PLAYBACK_SETTINGS'; });
              if (!hasGear) return result;
